// n8n Code node (Run Once for All Items)

// Toggle this to silence logs quickly
const DEBUG = true;

const log = (...args) => {
  if (DEBUG) console.log("[debug]", ...args);
};

const redact = (value) => {
  const SECRET_KEY_RE = /(token|secret|password|apiKey|key)/i;

  const walk = (v) => {
    if (v == null) return v;
    if (Array.isArray(v)) return v.map(walk);

    if (typeof v === "object") {
      const out = {};
      for (const [k, child] of Object.entries(v)) {
        if (SECRET_KEY_RE.test(k)) out[k] = "***REDACTED***";
        else out[k] = walk(child);
      }
      return out;
    }

    return v;
  };

  return walk(value);
};

log("Input item count:", $input.all().length);

const wrapper = $input.first().json;
log("Wrapper keys:", Object.keys(wrapper ?? {}));

const config = wrapper.config;
const event = wrapper.event;
const recipientsResolved = wrapper.recipientsResolved;

log("Has config?", !!config, "Has event?", !!event);
log("Config (redacted):", redact(config));
log("Event keys:", Object.keys(event ?? {}));
log("Event.body keys:", Object.keys(event?.body ?? {}));

if (!config) throw new Error("Missing config");
if (!event) throw new Error("Missing event");
if (!recipientsResolved) throw new Error("Missing RecipientsResolved");
if (!config?.recipients) throw new Error("Missing config.recipients (ConfigModel)");
if (!config?.endpoints) throw new Error("Missing config.endpoints (ConfigModel)");
if (!config?.templates) throw new Error("Missing config.templates (ConfigModel)");
if (!event?.body?.data?.type)
  throw new Error("Missing event.body.data.type (InboundDataModel discriminator)");
if (!event?.body?.device.id) throw new Error("Missing event.body.device.id");
if (!event?.body?.id) throw new Error("Missing event.body.id (eventId)");

const deviceId = event.body.device.id;
const dataType = event.body.data.type;
const eventId = event.body.id;

log("deviceId:", deviceId);
log("dataType:", dataType);
log("eventId:", eventId);

// meta is what templates typically refer to as {meta.*}
const meta = {
  id: event.body.id,
  createdAt: event.body.createdAt,
  deviceId: event.body.deviceId,
  source: event.body.source,
  ...(event.body.meta ?? {}),
};
log("meta:", meta);

const ensureAllExist = (kind, ids, registry) => {
  for (const id of ids) {
    if (!registry[id]) {
      throw new Error(`Unknown ${kind} id "${id}" referenced by routing logic`);
    }
  }
};

// Build OutboundDispatchPlan from config + event
const dispatches = [];
/**
 * @type {Array<Object>}
 */
const recipients = recipientsResolved;

log("recipient ids:", recipients.map((r) => r.id).flat().join(", "));

for (const recipient of recipientsResolved) {
  const recipientId = recipient.id;

  if (!Array.isArray(recipient.rules)) continue;

  for (const rule of recipient.rules) {
    const endpointIds = rule.then?.endpointIds ?? [];
    const templateIds = rule.then?.templateIds ?? [];

    if (endpointIds.length === 0 || templateIds.length === 0) continue;

    ensureAllExist("endpoint", endpointIds, config.endpoints);
    ensureAllExist("template", templateIds, config.templates);

    for (const endpointId of endpointIds) {
      for (const templateId of templateIds) {
        dispatches.push({
          id: `${eventId}:${recipientId}:${rule.id}:${endpointId}:${templateId}`,
          recipientId,
          ruleId: rule.id,
          endpointId,
          templateId,
          matchedRuleIds: [rule.id],
        });
      }
    }
  }
}

const outbound = {
  eventId,
  deviceId,
  dataType,
  configVersion: config.version,
  dispatches,
};

log("dispatches count:", dispatches.length);
log("outbound:", redact(outbound));

// Return RuntimeModel
return [
  {
    json: {
      event,
      config,
      outbound,
    },
  },
];

