const redact = (value) => {
  const SECRET_KEY_RE = /(token|secret|password|apiKey|key)/i;

  const walk = (v, path = '') => {
    if (v == null) return v;

    if (Array.isArray(v)) return v.map((x, i) => walk(x, `${path}[${i}]`));

    if (typeof v === 'object') {
      const out = {};
      for (const [k, child] of Object.entries(v)) {
        const full = path ? `${path}.${k}` : k;
        if (SECRET_KEY_RE.test(k)) out[k] = '***REDACTED***';
        else out[k] = walk(child, full);
      }
      return out;
    }

    return v;
  };

  return walk(value);
};

