};
log('meta:', meta);

const isPresent = (v) => v !== undefined && v !== null;

/**
  * If the value is a string, convert it to lowercase.
  * Otherwise, return the value as is.
  * @param {unknown} v - The value to be checked and potentially converted.
  * @returns {unknown | string} - The lowercase string or the original value.
 */
const normalizeIfString = (v) => {
  if (typeof v === 'string') {
    return v.trim().toLowerCase();
  }
  return v;
}

/**
 * Convert a value to a comparable number if possible.
 * @param {unknown} v - The value to be converted.
 * @returns {number | undefined} - The comparable number or undefined if conversion is not possible.
 */
const toComparableNumber = (v) => {
  if (typeof v === 'number' && Number.isFinite(v)) return v;
  if (typeof v === 'string' && normalizeIfString(v) !== '') {
    const n = Number(v);
    return Number.isFinite(n) ? n : undefined;
  }
  return undefined;
};

const normalizeEquals = (actual, expected) => {
  log('normalizeEquals:', { actual, expected, actualType: typeof actual, expectedType: typeof expected });

  if (!isPresent(actual) && !isPresent(expected)) return true;

  if (typeof actual === 'boolean') {
    if (typeof expected === 'boolean') return actual === expected;
    if (typeof expected === 'string') {
      const s = normalizeIfString(expected);
      if (s === 'true') return actual === true;
      if (s === 'false') return actual === false;
    }
    return false;
  }

  if (typeof actual === 'number') {
    const n = toComparableNumber(expected);
    return n !== undefined ? actual === n : false;
  }

  return normalizeIfString(String(actual)) === normalizeIfString(String(expected));
};

const getByPath = (root, path) => {
  const parts = (path ? String(path) : '')
    .split('.')
    .filter(Boolean);

  let cur = root;
  for (const part of parts) {
    if (cur == null) return undefined;
    cur = cur[part];
  }
  return cur;
};

// Uses "operator" (your current my.json)
const predicateMatches = (predicate) => {
  const op = predicate?.operator;
  const path = predicate?.path;
  const expected = predicate?.value;

  // Root lets your rules use paths like "deviceId" or "data.body" or "meta.device.id"
  const predicateRoot = { ...event.body, data: event.body.data, meta };
  const actual = getByPath(predicateRoot, path);

  log('predicate:', { path, op, expected, actual });

  switch (op) {
    case 'equals':
      return normalizeEquals(actual, expected);

    case 'not_equals':
      return !normalizeEquals(actual, expected);

    case 'includes': {
      if (!isPresent(actual)) return false;
      if (Array.isArray(actual)) return actual.includes(expected);
      return normalizeIfString(String(actual)).includes(normalizeIfString(String(expected ?? '')));
    }

    case 'not_includes': {
      if (!isPresent(actual)) return true;
      if (Array.isArray(actual)) return !actual.includes(expected);
      return !normalizeIfString(String(actual)).includes(normalizeIfString(String(expected ?? '')));
    }

    case 'starts_with':
      return isPresent(actual) && normalizeIfString(String(actual)).startsWith(normalizeIfString(String(expected ?? '')));

    case 'ends_with':
      return isPresent(actual) && normalizeIfString(String(actual)).endsWith(normalizeIfString(String(expected ?? '')));

    case 'matches_regex': {
      if (!isPresent(actual)) return false;
      try {
        const re = new RegExp(String(expected ?? ''));
        return re.test(String(actual));
      } catch {
        throw new Error(`Invalid regex in predicate for path "${path}": ${String(expected)}`);
      }
    }

    case 'gt':
    case 'gte':
    case 'lt':
    case 'lte': {
      const a = toComparableNumber(actual);
      const b = toComparableNumber(expected);
      log('numeric compare:', { op, a, b });
      if (a === undefined || b === undefined) return false;
      if (op === 'gt') return a > b;
      if (op === 'gte') return a >= b;
      if (op === 'lt') return a < b;
      return a <= b;
    }

    case 'exists':
      return isPresent(actual);

    default:
      throw new Error(`Unsupported predicate operator: ${op}`);
  }
};

const resolveRecipient = (recipientId, recipient) => {
  log('--- resolveRecipient ---', recipientId);
  log('recipient (redacted):', redact(recipient));

  const allowedDeviceIds = Array.isArray(recipient.allowedDeviceIds) ? recipient.allowedDeviceIds : [];
  log('allowedDeviceIds:', allowedDeviceIds);
  if (allowedDeviceIds.length > 0 && !allowedDeviceIds.includes(deviceId)) {
    log('SKIP: deviceId not allowed', { deviceId, allowedDeviceIds });
    return null;
  }

  const allowedDataTypes = Array.isArray(recipient.allowedDataTypes) ? recipient.allowedDataTypes : [];
  log('allowedDataTypes:', allowedDataTypes);
  if (allowedDataTypes.length > 0 && !allowedDataTypes.includes(dataType)) {
    log('SKIP: dataType not allowed', { dataType, allowedDataTypes });
    return null;
  }

  const baseEndpointIds = Array.isArray(recipient.endpointIds) ? recipient.endpointIds : [];
  const baseTemplateIds = Array.isArray(recipient.templateIds) ? recipient.templateIds : [];
  log('baseEndpointIds:', baseEndpointIds);
  log('baseTemplateIds:', baseTemplateIds);

  const rules = Array.isArray(recipient.rules) ? recipient.rules : [];
  log('rule count:', rules.length);

  if (rules.length === 0) {
    log('NO RULES: selecting recipient with base routing');
    return { id: recipientId, ...recipient, endpointIds: baseEndpointIds, templateIds: baseTemplateIds };
  }

  const matchedRules = [];

  for (const rule of rules) {
    log('checking rule:', { ruleId: rule?.id, type: rule?.type });

    if (rule?.type !== dataType) {
      log('rule type mismatch, skip:', { ruleType: rule?.type, dataType });
      continue;
    }

    const whens = Array.isArray(rule.when) ? rule.when : [];
    log('when predicates:', whens);

    const matched = whens.every((p, idx) => {
      const ok = predicateMatches(p);
      log(`predicate[${idx}] result:`, ok);
      return ok;
    });

    log('rule matched?', matched, 'ruleId:', rule?.id);

    if (!matched) continue;

    // IMPORTANT: keep track of matches (you were missing this)
    matchedRules.push(rule);
  }

  log('matchedRules ids:', matchedRules.map((r) => r.id));

  if (matchedRules.length === 0) {
    log('NO MATCHED RULES: dropping recipient');
    return null;
  }

  return { 
    id: recipientId,
    vars: recipient.vars,
    rules: matchedRules.map((r) => {
      return { id: r.id, then: r.then };
    }),
  };
};

log('recipient ids:', recipientsFilteredGlobally.join(", "));

const resolvedRecipients = recipientsFilteredGlobally
  .map((id) => resolveRecipient(id, config.recipients?.[id]))
  .filter(Boolean);

log('resolvedRecipients count:', resolvedRecipients.length);
log('resolvedRecipients (redacted):', redact(resolvedRecipients));

return [
  {
    json: {
      event,
      config,
      recipientsResolved: resolvedRecipients
    }
  }
];

