const getByPath = (root, path) => {
  if (!path || typeof path !== "string") return undefined;

  // supports simple dot paths like: meta.createdAt, data.body, recipient.vars.botToken
  const parts = path.split(".").filter(Boolean);
  let cur = root;

  for (const part of parts) {
    if (cur == null) return undefined;
    cur = cur[part];
  }

  return cur;
};

const templateString = (input, templateData, renderedText) => {
  if (typeof input !== "string") return input;

  return input.replace(/\{([^{}]+)\}/g, (match, rawToken) => {
    const token = String(rawToken).trim();

    // Special placeholder: {%text%} => already-rendered template.text
    if (token === "%text%") return String(renderedText ?? "");

    const value = getByPath(templateData, token);

    // If missing, keep placeholder as-is (non-strict)
    if (value === undefined || value === null) return match;

    // For non-primitives, stringify to avoid "[object Object]"
    if (typeof value === "object") return JSON.stringify(value);

    return String(value);
  });
};

const templateDeepOnlyStrings = (value, templateData, renderedText) => {
  if (typeof value === "string") return templateString(value, templateData, renderedText);

  if (Array.isArray(value)) {
    return value.map((v) => templateDeepOnlyStrings(v, templateData, renderedText));
  }

  if (value && typeof value === "object") {
    const out = {};
    for (const [k, v] of Object.entries(value)) {
      out[k] = templateDeepOnlyStrings(v, templateData, renderedText);
    }
    return out;
  }

  return value;
};

const items = $input.all().map((item) => {
  const wrapper = item.json;

  const config = wrapper.config;
  const event = wrapper.event;

  const templateData = wrapper.templateData;
  const toTemplate = wrapper.toTemplate;

  if (!templateData) throw new Error("Missing templateData");
  if (!toTemplate) throw new Error("Missing toTemplate");
  if (!toTemplate?.template?.text) throw new Error("Missing toTemplate.template.text");
  if (!toTemplate?.endpoint) throw new Error("Missing toTemplate.endpoint");

  // 1) Render template.text first (only uses templateData)
  const renderedText = templateString(toTemplate.template.text, templateData, "");

  // 2) Template ONLY within toTemplate (strings only), using templateData,
  //    with {%text%} resolved from the rendered template.text above.
  const templatedEndpoint = templateDeepOnlyStrings(
    toTemplate.endpoint,
    templateData,
    renderedText
  );

  // 3) Build "toSend" as a flattened, templated endpoint (no nesting)
  //    Keep everything else as-is; just add toSend.
  const toSend = {
    method: templatedEndpoint.method,
    url: templatedEndpoint.url,
    headers: templatedEndpoint.headers ?? {},
    searchParams: templatedEndpoint.searchParams ?? {},
    timeoutMs: templatedEndpoint.timeoutMs,
    body:
      templatedEndpoint?.body?.type === "json"
        ? (templatedEndpoint.body?.content ?? {})
        : templatedEndpoint?.body?.content ?? templatedEndpoint?.body,
  };

  log("Rendered text preview:", renderedText);
  log("toSend (redacted):", redact(toSend));

  return {
    json: {
      event,
      config,
      toSend,
    },
  };
});

return items;

