// Filters recipients by allowedDeviceIds / allowedDataTypes ONLY when those props exist.

const wrapper = $input.first().json;
const config = wrapper.config;
const event = wrapper.event;

if (!config?.recipients) throw new Error('Missing config.recipients');
if (!event?.body?.device?.id) throw new Error('Missing event.body.device.id');
if (!event?.body?.data?.type) throw new Error('Missing event.body.data.type');

const deviceId = event.body.device.id;
const dataType = event.body.data.type;


const isNotDisabled = (recipient) => {
  if (recipient.disabled === true) return false;
  return true;
};

const isAllowed = (recipient) => {
  // If prop is missing/null => do NOT filter by it (recipient remains)
  if (Array.isArray(recipient.allowedDeviceIds) && recipient.allowedDeviceIds.length > 0) {
    if (!recipient.allowedDeviceIds.includes(deviceId)) return false;
  }

  if (Array.isArray(recipient.allowedDataTypes) && recipient.allowedDataTypes.length > 0) {
    if (!recipient.allowedDataTypes.includes(dataType)) return false;
  }

  return true;
};

const out = Object.entries(config.recipients)
  .filter(([, recipient]) => isNotDisabled(recipient))
  .filter(([, recipient]) => isAllowed(recipient))
  .map(([id, recipient]) => (id));

return [
  {
    json: {
      event,
      config,
      recipientsFilteredGlobally: out
    }
  }
];

