    }

    // leave only unique
    rule.then.endpointIds.splice(0, rule.then.endpointIds.length, ...new Set(rule.then.endpointIds));

    // filter rules by recipient.templateIds (if any)
    /**
     * @type {Array<string>}
    */
    const ruleTemplateIds = [...rule.then.templateIds];

    if (recipientTemplateIds.length > 0 && ruleTemplateIds.length > 0) {
      if (recipientTemplateIds.some(item => ruleTemplateIds.includes(item))) {
        rule.then.templateIds = ruleTemplateIds.filter(id => recipientTemplateIds.includes(id));
        log(`Found matching templates for rule ${rule.id}:`, rule.then.templateIds);
      } else {
        const index = rulesFiltered.findIndex(r => r.id === rule.id);
        if (index > -1) {
          log(`No matching templates for rule ${rule.id}, removing it`);
          rulesFiltered.splice(index, 1);
        }
      }
    }

    // leave only unique
    rule.then.templateIds.splice(0, rule.then.templateIds.length, ...new Set(rule.then.templateIds));

    log(`Recipient ${recipient.id} filtered rules:`, recipient.rules.length, "->", rulesFiltered.length);

    recipient.rules = rulesFiltered;
  }
}

// Return RuntimeModel
return [
  {
    json: {
      event,
      config,
      recipientsResolved
    }
  }
];

